mapper.select:
SELECT count(*) FROM heatexchangerunit AS u
LEFT JOIN heatexchangestation AS s ON u.StationID = s.id INNER JOIN rtustation AS rtu ON rtu.stationID = s.id INNER JOIN company AS c ON c.id = s.CompanyID
AND s.`CompanyID`=#{companyID}
AND s.`id`=#{stationID}

SELECT u.id, s.CompanyID as companyID, s.id as stationID, u.UnitSqu as subID, c.Name as companyName, s.Name as stationName, rtu.stationCode as stationCode, u.unitNumber as unitName, u.UpdateDesc as mem FROM heatexchangerunit AS u LEFT JOIN heatexchangestation AS s ON u.StationID = s.id INNER JOIN rtustation AS rtu ON rtu.stationID = s.id INNER JOIN company AS c ON c.id = s.CompanyID
AND s.`CompanyID`=#{companyID}
order by u.id limit #{offset},#{pageSize}
